body:
Let's assume I have a c++ testbench which uses internal Verilator functions, I would like to compile this into a shared library rather an executable. 

Assume the following minimal example:
```
mkdir test_our
cd test_our

cat >our.v <<'EOF'
  module our;
     initial begin $display("Hello World"); $finish; end
  endmodule
EOF

cat >sim_main.cpp <<'EOF'
  #include "Vour.h"
  #include "verilated.h"
  int main(int argc, char** argv) {
      VerilatedContext* contextp = new VerilatedContext;
      contextp->commandArgs(argc, argv);
      Vour* top = new Vour{contextp};
      while (!contextp->gotFinish()) { top->eval(); }
      delete top;
      delete contextp;
      return 0;
  }
EOF
```
Compiled with:
```
verilator --cc --exe --build -j 0 -Wall sim_main.cpp our.v
```

Instead of compiling this function as an executable, I would like for it be compiled into a static library that I can then link into another codebase. Something like this:
```
 #include "Vour.h"
  #include "verilated.h"
  int simulate(int argc, char** argv) {
      VerilatedContext* contextp = new VerilatedContext;
      contextp->commandArgs(argc, argv);
      Vour* top = new Vour{contextp};
      while (!contextp->gotFinish()) { top->eval(); }
      delete top;
      delete contextp;
      return 0;
  }
```
And then the library should expose the `simulate` symbols. Is this possible? If so, is there a specific verilator flag I can use to do so?
